Here are the public test cases for feature1_1_directory_create:
{
  "description": "Create directories. A directory can be created at a path whose parent already exists; creating it recursively also materializes any missing ancestor directories. Creating a directory that already exists as a directory is a no-op success. The created directory's path is echoed back.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/foo"
          },
          {
            "op": "exists",
            "path": "/foo",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/foo\nexists=true\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/a/b/c",
            "recursive": true
          },
          {
            "op": "exists",
            "path": "/a/b/c",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/a/b/c\nexists=true\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/a/b/c"
          }
        ]
      },
      "expected_output": "error=no_such_file_or_directory\n"
    }
  ]
}

Here are the public test cases for feature1_3_directory_delete:
{
  "description": "Delete a directory. A non-recursive delete succeeds only when the directory is empty; deleting a non-empty directory non-recursively fails with a directory-not-empty category. A recursive delete removes the directory and all of its contents. The deleted path is echoed back.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/d"
          },
          {
            "op": "delete",
            "path": "/d",
            "as": "directory"
          },
          {
            "op": "exists",
            "path": "/d",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/d\ndeleted=/d\nexists=false\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/foo"
          },
          {
            "op": "create_file",
            "path": "/foo/x"
          },
          {
            "op": "delete",
            "path": "/foo",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/foo\ncreated_file=/foo/x\nerror=directory_not_empty\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/foo"
          },
          {
            "op": "create_file",
            "path": "/foo/x"
          },
          {
            "op": "delete",
            "path": "/foo",
            "as": "directory",
            "recursive": true
          },
          {
            "op": "exists",
            "path": "/foo",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/foo\ncreated_file=/foo/x\ndeleted=/foo\nexists=false\n"
    }
  ]
}

Here are the public test cases for feature1_4_directory_rename:
{
  "description": "Rename (move) a directory to a new path. Renaming onto a path whose parent does not exist fails, and renaming a source that does not exist fails, both with a not-found category. A successful rename reports the new path.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/a"
          },
          {
            "op": "rename",
            "from": "/a",
            "to": "/b",
            "as": "directory"
          },
          {
            "op": "exists",
            "path": "/b",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/a\nrenamed=/b\nexists=true\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "rename",
            "from": "/nope",
            "to": "/b",
            "as": "directory"
          }
        ]
      },
      "expected_output": "error=no_such_file_or_directory\n"
    }
  ]
}

Here are the public test cases for feature2_1_file_text:
{
  "description": "Write a string to a file and read it back as text. Writing reports the number of bytes (UTF-8 encoded) written; reading returns the JSON-quoted text content. Reading a zero-byte file yields an empty string.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_file",
            "path": "/foo/bar.txt",
            "recursive": true
          },
          {
            "op": "write",
            "path": "/foo/bar.txt",
            "text": "hello"
          },
          {
            "op": "read",
            "path": "/foo/bar.txt"
          },
          {
            "op": "length",
            "path": "/foo/bar.txt"
          }
        ]
      },
      "expected_output": "created_file=/foo/bar.txt\nwrote_bytes=5\ntext=\"hello\"\nlength=5\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_file",
            "path": "/e"
          },
          {
            "op": "read",
            "path": "/e"
          }
        ]
      },
      "expected_output": "created_file=/e\ntext=\"\"\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "write",
            "path": "/u.txt",
            "text": "héllo"
          },
          {
            "op": "read",
            "path": "/u.txt"
          },
          {
            "op": "length",
            "path": "/u.txt"
          }
        ]
      },
      "expected_output": "wrote_bytes=6\ntext=\"héllo\"\nlength=6\n"
    }
  ]
}

