    {
      "input": {
        "ops": [
          {
            "op": "write",
            "path": "/a",
            "text": "new"
          },
          {
            "op": "write",
            "path": "/b",
            "text": "old"
          },
          {
            "op": "copy",
            "from": "/a",
            "to": "/b"
          },
          {
            "op": "read",
            "path": "/b"
          }
        ]
      },
      "expected_output": "wrote_bytes=3\nwrote_bytes=3\ncopied=/b\ntext=\"new\"\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "copy",
            "from": "/nope",
            "to": "/b"
