Here are the public test cases for feature5_1_raf_sequential:
{
  "description": "Open a file handle and write bytes/text sequentially, then read them back. Writing reports the number of bytes written; the handle's length reflects accumulated writes. A single byte value can also be written and read back as raw bytes.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_file",
            "path": "/f"
          },
          {
            "op": "open",
            "path": "/f",
            "handle": "h",
            "mode": "write"
          },
          {
            "op": "raf_write",
            "handle": "h",
            "text": "hello"
          },
          {
            "op": "raf_length",
            "handle": "h"
          },
          {
            "op": "raf_close",
            "handle": "h"
          },
          {
            "op": "read",
            "path": "/f"
          }
        ]
      },
      "expected_output": "created_file=/f\nopened=/f\nwrote_bytes=5\nlength=5\nclosed=h\ntext=\"hello\"\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_file",
            "path": "/f"
          },
          {
            "op": "open",
            "path": "/f",
            "handle": "h",
            "mode": "write"
          },
          {
            "op": "raf_write_byte",
            "handle": "h",
            "value": 65
          },
          {
            "op": "raf_close",
            "handle": "h"
          },
          {
            "op": "read",
            "path": "/f",
            "as": "bytes"
          }
        ]
      },
      "expected_output": "created_file=/f\nopened=/f\nwrote_bytes=1\nclosed=h\nbytes=65\n"
    }
  ]
}

Here are the public test cases for feature5_2_raf_position:
{
  "description": "A file handle tracks a read/write cursor position. Reading advances the position; the cursor can be repositioned to an absolute offset and subsequent reads start from there. Reading more bytes than remain returns only the available bytes.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "write",
            "path": "/f",
            "text": "hello"
          },
          {
            "op": "open",
            "path": "/f",
            "handle": "h",
            "mode": "read"
          },
          {
            "op": "raf_read_byte",
            "handle": "h"
          },
          {
            "op": "raf_position",
            "handle": "h"
          },
          {
            "op": "raf_set_position",
            "handle": "h",
            "position": 0
          },
          {
            "op": "raf_read",
            "handle": "h",
            "count": 5
          }
        ]
      },
      "expected_output": "wrote_bytes=5\nopened=/f\nread_byte=104\nposition=1\nposition=0\nread_length=5\nread_text=\"hello\"\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "write",
            "path": "/f",
            "text": "hi"
          },
          {
            "op": "open",
            "path": "/f",
            "handle": "h",
            "mode": "read"
          },
          {
            "op": "raf_read",
            "handle": "h",
            "count": 10
          }
        ]
      },
      "expected_output": "wrote_bytes=2\nopened=/f\nread_length=2\nread_text=\"hi\"\n"
    }
  ]
}

